def prove_minimp_pm2_43(sys: System) -> Proof:
    """Derivation of ~ pm2.43 (also called "hilbert" or W) from ~ ax-mp and
    ~ minimp .  It uses the classical derivation from ~ ax-1 and ~ ax-2
    written DD22D21 in D-notation (see head comment for an explanation) and
    shortens the proof using ~ mp2 (which only requires ~ ax-mp ).
    (Contributed by BJ, 31-May-2021.)  (Proof modification is discouraged.)
    (New usage is discouraged.)
    """
    lb = ProofBuilder(sys, "minimp-pm2.43")
    s1 = lb.ref("s1", "( ( φ → ( φ → ψ ) ) → ( ( φ → φ ) → ( φ → ψ ) ) )", ref="minimp-ax2", note="minimp-ax2")
    s2 = lb.ref("s2", "( φ → ( ( φ → ψ ) → φ ) )", ref="minimp-ax1", note="minimp-ax1")
    s3 = lb.ref("s3", "( ( φ → ( ( φ → ψ ) → φ ) ) → ( ( φ → ( φ → ψ ) ) → ( φ → φ ) ) )", ref="minimp-ax2", note="minimp-ax2")
    s4 = lb.mp("s4", s2, s3, "ax-mp")
    s5 = lb.ref("s5", "( ( ( φ → ( φ → ψ ) ) → ( ( φ → φ ) → ( φ → ψ ) ) ) → ( ( ( φ → ( φ → ψ ) ) → ( φ → φ ) ) → ( ( φ → ( φ → ψ ) ) → ( φ → ψ ) ) ) )", ref="minimp-ax2", note="minimp-ax2")
    res = lb.ref("res", "( ( φ → ( φ → ψ ) ) → ( φ → ψ ) )", s1, s4, s5, ref="mp2", note="mp2")
    return lb.build(res)

def prove_impsingle(sys: System) -> Proof:
    """The shortest single axiom for implicational calculus, due to Lukasiewicz.
    It is now known to be the _unique_ shortest axiom.  The axiom is proved
    here starting from { ~ ax-1 , ~ ax-2 and ~ peirce }.  (Contributed by
    Larry Lesyna and Jeffrey P. Machado, 18-Jul-2023.)
    (Proof modification is discouraged.)  (New usage is discouraged.)
    """
    lb = ProofBuilder(sys, "impsingle")
    s1 = lb.ref("s1", "( ( ( φ → ψ ) → χ ) → ( ( χ → φ ) → ( ( φ → ψ ) → φ ) ) )", ref="imim1", note="imim1")
    s2 = lb.ref("s2", "( ( ( φ → ψ ) → φ ) → φ )", ref="peirce", note="peirce")
    s3 = lb.ref("s3", "( ( ( φ → ψ ) → φ ) → ( θ → φ ) )", s2, ref="a1d", note="a1d")
    res = lb.ref("res", "( ( ( φ → ψ ) → χ ) → ( ( χ → φ ) → ( θ → φ ) ) )", s1, s3, ref="syl6", note="syl6")
    return lb.build(res)

def prove_impsingle_step4(sys: System) -> Proof:
    """Derivation of impsingle-step4 from ~ ax-mp and ~ impsingle .  It is used
    as a lemma in proofs of ~ imim1 and ~ peirce from ~ impsingle .  It is
    Step 4 in Lukasiewicz, where it appears as 'CCCpqpCsp' using
    parenthesis-free prefix notation.  (Contributed by Larry Lesyna and
    Jeffrey P. Machado, 2-Aug-2023.)  (Proof modification is discouraged.)
    (New usage is discouraged.)
    """
    lb = ProofBuilder(sys, "impsingle-step4")
    s1 = lb.ref("s1", "( ( ( τ → η ) → ζ ) → ( ( ζ → τ ) → ( σ → τ ) ) )", ref="impsingle", note="impsingle")
    s2 = lb.ref("s2", "( ( ( φ → θ ) → ( φ → ψ ) ) → ( ( ( φ → ψ ) → φ ) → ( χ → φ ) ) )", ref="impsingle", note="impsingle")
    s3 = lb.ref("s3", "( ( ( φ → ψ ) → ( φ → ψ ) ) → ( ( ( φ → ψ ) → φ ) → ( χ → φ ) ) )", ref="impsingle", note="impsingle")
    s4 = lb.ref("s4", "( ( ( ( φ → ψ ) → ( φ → ψ ) ) → ( ( ( φ → ψ ) → φ ) → ( χ → φ ) ) ) → ( ( ( ( ( φ → ψ ) → φ ) → ( χ → φ ) ) → ( φ → ψ ) ) → ( ( φ → θ ) → ( φ → ψ ) ) ) )", ref="impsingle", note="impsingle")
    s5 = lb.mp("s5", s3, s4, "ax-mp")
    s6 = lb.ref("s6", "( ( ( ( ( ( φ → ψ ) → φ ) → ( χ → φ ) ) → ( φ → ψ ) ) → ( ( φ → θ ) → ( φ → ψ ) ) ) → ( ( ( ( φ → θ ) → ( φ → ψ ) ) → ( ( ( φ → ψ ) → φ ) → ( χ → φ ) ) ) → ( ( ( ( τ → η ) → ζ ) → ( ( ζ → τ ) → ( σ → τ ) ) ) → ( ( ( φ → ψ ) → φ ) → ( χ → φ ) ) ) ) )", ref="impsingle", note="impsingle")
    s7 = lb.mp("s7", s5, s6, "ax-mp")
    s8 = lb.mp("s8", s2, s7, "ax-mp")
    res = lb.mp("res", s1, s8, "ax-mp")
    return lb.build(res)

def prove_impsingle_step8(sys: System) -> Proof:
    """Derivation of impsingle-step8 from ~ ax-mp and ~ impsingle .  It is used
    as a lemma in proofs of ~ ax-1 ~ imim1 and ~ peirce from ~ impsingle .  It
    is Step 8 in Lukasiewicz, where it appears as 'CCCsqpCqp' using
    parenthesis-free prefix notation.  (Contributed by Larry Lesyna and
    Jeffrey P. Machado, 2-Aug-2023.)  (Proof modification is discouraged.)
    (New usage is discouraged.)
    """
    lb = ProofBuilder(sys, "impsingle-step8")
    s1 = lb.ref("s1", "( ( ( τ → η ) → ζ ) → ( ( ζ → τ ) → ( σ → τ ) ) )", ref="impsingle", note="impsingle")
    s2 = lb.ref("s2", "( ( ( χ → θ ) → ( φ → ψ ) ) → ( ( ( φ → ψ ) → χ ) → ( ψ → χ ) ) )", ref="impsingle", note="impsingle")
    s3 = lb.ref("s3", "( ( ( τ → η ) → ζ ) → ( ( ζ → τ ) → ( σ → τ ) ) )", ref="impsingle", note="impsingle")
    s4 = lb.ref("s4", "( ( ( ψ → θ ) → ( ψ → χ ) ) → ( ( ( ψ → χ ) → ψ ) → ( φ → ψ ) ) )", ref="impsingle", note="impsingle")
