def prove_impsingle_peirce(sys: System) -> Proof:
    """Derivation of impsingle-peirce ( ~ peirce ) from ~ ax-mp and ~ impsingle .
    It is step 28 in Lukasiewicz.  (Contributed by Larry Lesyna and Jeffrey P.
    Machado, 2-Aug-2023.)  (Proof modification is discouraged.)
    (New usage is discouraged.)
    """
    lb = ProofBuilder(sys, "impsingle-peirce")
    s1 = lb.ref("s1", "( φ → φ )", ref="impsingle-step22", note="impsingle-step22")
    s2 = lb.ref("s2", "( ( φ → φ ) → ( ( ( φ → ψ ) → φ ) → φ ) )", ref="impsingle-step25", note="impsingle-step25")
    res = lb.mp("res", s1, s2, "ax-mp")
    return lb.build(res)

