    lb = ProofBuilder(sys, "merlem3")
    s1 = lb.ref("s1", "( ( ( ¬ χ → ¬ χ ) → ( ¬ χ → ¬ χ ) ) → ( ( φ → φ ) → ( ¬ χ → ¬ χ ) ) )", ref="merlem2", note="merlem2")
    s2 = lb.ref("s2", "( ( ( ( ¬ χ → ¬ χ ) → ( ¬ χ → ¬ χ ) ) → ( ( φ → φ ) → ( ¬ χ → ¬ χ ) ) ) → ( ( ( ( χ → φ ) → ( ¬ ψ → ¬ ψ ) ) → ψ ) → ( ( φ → φ ) → ( ¬ χ → ¬ χ ) ) ) )", ref="merlem2", note="merlem2")
    s3 = lb.mp("s3", s1, s2, "ax-mp")
    s4 = lb.ref("s4", "( ( ( ( ( χ → φ ) → ( ¬ ψ → ¬ ψ ) ) → ψ ) → ( ( φ → φ ) → ( ¬ χ → ¬ χ ) ) ) → ( ( ( ( φ → φ ) → ( ¬ χ → ¬ χ ) ) → χ ) → ( ψ → χ ) ) )", ref="meredith", note="meredith")
    s5 = lb.mp("s5", s3, s4, "ax-mp")
    s6 = lb.ref("s6", "( ( ( ( ( φ → φ ) → ( ¬ χ → ¬ χ ) ) → χ ) → ( ψ → χ ) ) → ( ( ( ψ → χ ) → φ ) → ( χ → φ ) ) )", ref="meredith", note="meredith")
    res = lb.mp("res", s5, s6, "ax-mp")
