    s1 = lb.ref("s1", "( ( ¬ ( ( ¬ φ → φ ) → φ ) → ( ( ¬ φ → φ ) → φ ) ) → ( ( ¬ φ → φ ) → φ ) )", ref="luk-2", note="luk-2")
    s2 = lb.ref("s2", "( ( ¬ φ → φ ) → φ )", ref="luk-2", note="luk-2")
    s3 = lb.ref("s3", "( ( ( ¬ φ → φ ) → φ ) → ( ( ( ¬ ( ( ¬ φ → φ ) → φ ) → ( ( ¬ φ → φ ) → φ ) ) → ( ( ¬ φ → φ ) → φ ) ) → ( ¬ ψ → ( ( ¬ φ → φ ) → φ ) ) ) )", ref="luklem3", note="luklem3")
    s4 = lb.mp("s4", s2, s3, "ax-mp")
    s5 = lb.mp("s5", s1, s4, "ax-mp")
    s6 = lb.ref("s6", "( ( ¬ ψ → ( ( ¬ φ → φ ) → φ ) ) → ( ( ( ( ¬ φ → φ ) → φ ) → ψ ) → ( ¬ ψ → ψ ) ) )", ref="luk-1", note="luk-1")
    s7 = lb.mp("s7", s5, s6, "ax-mp")
    s8 = lb.ref("s8", "( ( ¬ ψ → ψ ) → ψ )", ref="luk-2", note="luk-2")
    res = lb.ref("res", "( ( ( ( ¬ φ → φ ) → φ ) → ψ ) → ψ )", s7, s8, ref="luklem1", note="luklem1")
    return lb.build(res)

