def prove_nic_dfim(sys: System) -> Proof:
    """This theorem "defines" implication in terms of 'nand'.  Analogous to
    ~ nanim .  In a pure (standalone) treatment of Nicod's axiom, this theorem
    would be changed to a definition ($a statement).  (Contributed by NM,
    11-Dec-2008.)  (Proof modification is discouraged.)
    (New usage is discouraged.)
    """
    lb = ProofBuilder(sys, "nic-dfim")
    s1 = lb.ref("s1", "( ( φ → ψ ) ↔ ( φ ⊼ ( ψ ⊼ ψ ) ) )", ref="nanim", note="nanim")
    s2 = lb.ref("s2", "( ( φ ⊼ ( ψ ⊼ ψ ) ) ↔ ( φ → ψ ) )", s1, ref="bicomi", note="bicomi")
    s3 = lb.ref("s3", "( ( ( φ ⊼ ( ψ ⊼ ψ ) ) ↔ ( φ → ψ ) ) ↔ ( ( ( φ ⊼ ( ψ ⊼ ψ ) ) ⊼ ( φ → ψ ) ) ⊼ ( ( ( φ ⊼ ( ψ ⊼ ψ ) ) ⊼ ( φ ⊼ ( ψ ⊼ ψ ) ) ) ⊼ ( ( φ → ψ ) ⊼ ( φ → ψ ) ) ) ) )", ref="nanbi", note="nanbi")
    res = lb.ref("res", "( ( ( φ ⊼ ( ψ ⊼ ψ ) ) ⊼ ( φ → ψ ) ) ⊼ ( ( ( φ ⊼ ( ψ ⊼ ψ ) ) ⊼ ( φ ⊼ ( ψ ⊼ ψ ) ) ) ⊼ ( ( φ → ψ ) ⊼ ( φ → ψ ) ) ) )", s2, s3, ref="mpbi", note="mpbi")
    return lb.build(res)

def prove_nic_dfneg(sys: System) -> Proof:
    """This theorem "defines" negation in terms of 'nand'.  Analogous to
    ~ nannot .  In a pure (standalone) treatment of Nicod's axiom, this
    theorem would be changed to a definition ($a statement).  (Contributed by
    NM, 11-Dec-2008.)  (Proof modification is discouraged.)
    (New usage is discouraged.)
    """
    lb = ProofBuilder(sys, "nic-dfneg")
    s1 = lb.ref("s1", "( ¬ φ ↔ ( φ ⊼ φ ) )", ref="nannot", note="nannot")
    s2 = lb.ref("s2", "( ( φ ⊼ φ ) ↔ ¬ φ )", s1, ref="bicomi", note="bicomi")
    s3 = lb.ref("s3", "( ( ( φ ⊼ φ ) ↔ ¬ φ ) ↔ ( ( ( φ ⊼ φ ) ⊼ ( ¬ φ ) ) ⊼ ( ( ( φ ⊼ φ ) ⊼ ( φ ⊼ φ ) ) ⊼ ( ( ¬ φ ) ⊼ ( ¬ φ ) ) ) ) )", ref="nanbi", note="nanbi")
    res = lb.ref("res", "( ( ( φ ⊼ φ ) ⊼ ( ¬ φ ) ) ⊼ ( ( ( φ ⊼ φ ) ⊼ ( φ ⊼ φ ) ) ⊼ ( ( ¬ φ ) ⊼ ( ¬ φ ) ) ) )", s2, s3, ref="mpbi", note="mpbi")
    return lb.build(res)

def prove_nic_mp(sys: System) -> Proof:
    """Derive Nicod's rule of modus ponens using 'nand', from the standard one.
    Although the major and minor premise together also imply ` ch ` , this
    form is necessary for useful derivations from ~ nic-ax .  In a pure
    (standalone) treatment of Nicod's axiom, this theorem would be changed
    to an axiom ($a statement).  (Contributed by Jeff Hoffman, 19-Nov-2007.)
    (Proof modification is discouraged.)  (New usage is discouraged.)
    """
    lb = ProofBuilder(sys, "nic-mp")
    h1 = lb.hyp("nic-jmin", "φ")
    h2 = lb.hyp("nic-jmaj", "( φ ⊼ ( χ ⊼ ψ ) )")
    s1 = lb.ref("s1", "( ( φ ⊼ ( χ ⊼ ψ ) ) ↔ ( φ → ( χ ∧ ψ ) ) )", ref="nannan", note="nannan")
    s2 = lb.ref("s2", "( φ → ( χ ∧ ψ ) )", h2, s1, ref="mpbi", note="mpbi")
    s3 = lb.ref("s3", "( φ → ψ )", s2, ref="simprd", note="simprd")
    res = lb.mp("res", h1, s3, "ax-mp")
    return lb.build(res)

def prove_nic_mpALT(sys: System) -> Proof:
    """A direct proof of ~ nic-mp .  (Contributed by NM, 30-Dec-2008.)
    (Proof modification is discouraged.)  (New usage is discouraged.)
    """
    lb = ProofBuilder(sys, "nic-mpALT")
    h1 = lb.hyp("nic-jmin", "φ")
    h2 = lb.hyp("nic-jmaj", "( φ ⊼ ( χ ⊼ ψ ) )")
    s1 = lb.ref("s1", "( ( φ ⊼ ( χ ⊼ ψ ) ) ↔ ¬ ( φ ∧ ( χ ⊼ ψ ) ) )", ref="df-nan", note="df-nan")
    s2 = lb.ref("s2", "( ( χ ⊼ ψ ) ↔ ¬ ( χ ∧ ψ ) )", ref="df-nan", note="df-nan")
    s3 = lb.ref("s3", "( ( φ ∧ ( χ ⊼ ψ ) ) ↔ ( φ ∧ ¬ ( χ ∧ ψ ) ) )", s2, ref="anbi2i", note="anbi2i")
    s4 = lb.ref("s4", "( ( φ ⊼ ( χ ⊼ ψ ) ) ↔ ¬ ( φ ∧ ¬ ( χ ∧ ψ ) ) )", s1, s3, ref="xchbinx", note="xchbinx")
    s5 = lb.ref("s5", "¬ ( φ ∧ ¬ ( χ ∧ ψ ) )", h2, s4, ref="mpbi", note="mpbi")
    s6 = lb.ref("s6", "( ( φ → ( χ ∧ ψ ) ) ↔ ¬ ( φ ∧ ¬ ( χ ∧ ψ ) ) )", ref="iman", note="iman")
    s7 = lb.ref("s7", "( φ → ( χ ∧ ψ ) )", s5, s6, ref="mpbir", note="mpbir")
    s8 = lb.ref("s8", "( φ → ψ )", s7, ref="simprd", note="simprd")
    res = lb.mp("res", h1, s8, "ax-mp")
    return lb.build(res)

def prove_nic_ax(sys: System) -> Proof:
    """Nicod's axiom derived from the standard ones.  See _Introduction to
    Mathematical Philosophy_ by B. Russell, p. 152.  Like ~ meredith , the
    usual axioms can be derived from this and vice versa.  Unlike ~ meredith ,
    Nicod uses a different connective ('nand'), so another form of modus
    ponens must be used in proofs, e.g., ` { ` ~ nic-ax , ~ nic-mp ` } ` is
    equivalent to ` { ` ~ luk-1 , ~ luk-2 , ~ luk-3 , ~ ax-mp ` } ` .  In a
    pure (standalone) treatment of Nicod's axiom, this theorem would be
    changed to an axiom ($a statement).  (Contributed by Jeff Hoffman,
    19-Nov-2007.)  (Proof modification is discouraged.)
    (New usage is discouraged.)
    """
    lb = ProofBuilder(sys, "nic-ax")
    s1 = lb.ref("s1", "( ( φ ⊼ ( χ ⊼ ψ ) ) ↔ ( φ → ( χ ∧ ψ ) ) )", ref="nannan", note="nannan")
    s2 = lb.ref("s2", "( ( φ ⊼ ( χ ⊼ ψ ) ) → ( φ → ( χ ∧ ψ ) ) )", s1, ref="biimpi", note="biimpi")
    s3 = lb.ref("s3", "( ( χ ∧ ψ ) → χ )", ref="simpl", note="simpl")
    s4 = lb.ref("s4", "( ( φ → ( χ ∧ ψ ) ) → ( φ → χ ) )", s3, ref="imim2i", note="imim2i")
    s5 = lb.ref("s5", "( ( θ → ¬ χ ) ↔ ¬ ( θ ∧ χ ) )", ref="imnan", note="imnan")
    s6 = lb.ref("s6", "( ( θ ⊼ χ ) ↔ ¬ ( θ ∧ χ ) )", ref="df-nan", note="df-nan")
    s7 = lb.ref("s7", "( ( θ → ¬ χ ) ↔ ( θ ⊼ χ ) )", s5, s6, ref="bitr4i", note="bitr4i")
    s8 = lb.ref("s8", "( ( φ → χ ) → ( ¬ χ → ¬ φ ) )", ref="con3", note="con3")
    s9 = lb.ref("s9", "( ( φ → χ ) → ( ( θ → ¬ χ ) → ( θ → ¬ φ ) ) )", s8, ref="imim2d", note="imim2d")
    s10 = lb.ref("s10", "( ( φ → ¬ θ ) ↔ ¬ ( φ ∧ θ ) )", ref="imnan", note="imnan")
    s11 = lb.ref("s11", "( ( θ → ¬ φ ) ↔ ( φ → ¬ θ ) )", ref="con2b", note="con2b")
    s12 = lb.ref("s12", "( ( φ ⊼ θ ) ↔ ¬ ( φ ∧ θ ) )", ref="df-nan", note="df-nan")
    s13 = lb.ref("s13", "( ( φ ⊼ θ ) ↔ ( θ → ¬ φ ) )", s10, s11, s12, ref="3bitr4ri", note="3bitr4ri")
    s14 = lb.ref("s14", "( ( φ → χ ) → ( ( θ → ¬ χ ) → ( φ ⊼ θ ) ) )", s9, s13, ref="imbitrrdi", note="imbitrrdi")
    s15 = lb.ref("s15", "( ( φ → χ ) → ( ( θ ⊼ χ ) → ( φ ⊼ θ ) ) )", s7, s14, ref="biimtrrid", note="biimtrrid")
    s16 = lb.ref("s16", "( ( ( θ ⊼ χ ) → ( φ ⊼ θ ) ) ↔ ( ( θ ⊼ χ ) ⊼ ( ( φ ⊼ θ ) ⊼ ( φ ⊼ θ ) ) ) )", ref="nanim", note="nanim")
    s17 = lb.ref("s17", "( ( φ → χ ) → ( ( θ ⊼ χ ) ⊼ ( ( φ ⊼ θ ) ⊼ ( φ ⊼ θ ) ) ) )", s15, s16, ref="sylib", note="sylib")
    s18 = lb.ref("s18", "( ( φ ⊼ ( χ ⊼ ψ ) ) → ( ( θ ⊼ χ ) ⊼ ( ( φ ⊼ θ ) ⊼ ( φ ⊼ θ ) ) ) )", s2, s4, s17, ref="3syl", note="3syl")
    s19 = lb.ref("s19", "( τ ↔ ( τ ∧ τ ) )", ref="pm4.24", note="pm4.24")
    s20 = lb.ref("s20", "( τ → ( τ ∧ τ ) )", s19, ref="biimpi", note="biimpi")
    s21 = lb.ref("s21", "( ( τ ⊼ ( τ ⊼ τ ) ) ↔ ( τ → ( τ ∧ τ ) ) )", ref="nannan", note="nannan")
    s22 = lb.ref("s22", "( τ ⊼ ( τ ⊼ τ ) )", s20, s21, ref="mpbir", note="mpbir")
    s23 = lb.ref("s23", "( ( φ ⊼ ( χ ⊼ ψ ) ) → ( ( τ ⊼ ( τ ⊼ τ ) ) ∧ ( ( θ ⊼ χ ) ⊼ ( ( φ ⊼ θ ) ⊼ ( φ ⊼ θ ) ) ) ) )", s18, s22, ref="jctil", note="jctil")
    s24 = lb.ref("s24", "( ( ( φ ⊼ ( χ ⊼ ψ ) ) ⊼ ( ( τ ⊼ ( τ ⊼ τ ) ) ⊼ ( ( θ ⊼ χ ) ⊼ ( ( φ ⊼ θ ) ⊼ ( φ ⊼ θ ) ) ) ) ) ↔ ( ( φ ⊼ ( χ ⊼ ψ ) ) → ( ( τ ⊼ ( τ ⊼ τ ) ) ∧ ( ( θ ⊼ χ ) ⊼ ( ( φ ⊼ θ ) ⊼ ( φ ⊼ θ ) ) ) ) ) )", ref="nannan", note="nannan")
    res = lb.ref("res", "( ( φ ⊼ ( χ ⊼ ψ ) ) ⊼ ( ( τ ⊼ ( τ ⊼ τ ) ) ⊼ ( ( θ ⊼ χ ) ⊼ ( ( φ ⊼ θ ) ⊼ ( φ ⊼ θ ) ) ) ) )", s23, s24, ref="mpbir", note="mpbir")
    return lb.build(res)

def prove_nic_axALT(sys: System) -> Proof:
    """A direct proof of ~ nic-ax .  (Contributed by NM, 11-Dec-2008.)
    (Proof modification is discouraged.)  (New usage is discouraged.)
    """
    lb = ProofBuilder(sys, "nic-axALT")
    s1 = lb.ref("s1", "( ( χ ∧ ψ ) → χ )", ref="simpl", note="simpl")
    s2 = lb.ref("s2", "( ( φ → ( χ ∧ ψ ) ) → ( φ → χ ) )", s1, ref="imim2i", note="imim2i")
    s3 = lb.ref("s3", "( ( φ → χ ) → ( ¬ χ → ¬ φ ) )", ref="con3", note="con3")
    s4 = lb.ref("s4", "( ( φ → χ ) → ( ( θ → ¬ χ ) → ( θ → ¬ φ ) ) )", s3, ref="imim2d", note="imim2d")
    s5 = lb.ref("s5", "( ( φ → ( χ ∧ ψ ) ) → ( ( θ → ¬ χ ) → ( θ → ¬ φ ) ) )", s2, s4, ref="syl", note="syl")
    s6 = lb.ref("s6", "( ( τ ∧ τ ) ↔ τ )", ref="anidm", note="anidm")
    s7 = lb.ref("s7", "( τ → ( τ ∧ τ ) )", s6, ref="biimpri", note="biimpri")
    s8 = lb.ref("s8", "( ( φ → ( χ ∧ ψ ) ) → ( ( τ → ( τ ∧ τ ) ) ∧ ( ( θ → ¬ χ ) → ( θ → ¬ φ ) ) ) )", s5, s7, ref="jctil", note="jctil")
    s9 = lb.ref("s9", "( ( χ ⊼ ψ ) ↔ ¬ ( χ ∧ ψ ) )", ref="df-nan", note="df-nan")
    s10 = lb.ref("s10", "( ( φ ∧ ( χ ⊼ ψ ) ) ↔ ( φ ∧ ¬ ( χ ∧ ψ ) ) )", s9, ref="anbi2i", note="anbi2i")
    s11 = lb.ref("s11", "( ¬ ( φ ∧ ( χ ⊼ ψ ) ) ↔ ¬ ( φ ∧ ¬ ( χ ∧ ψ ) ) )", s10, ref="notbii", note="notbii")
    s12 = lb.ref("s12", "( ( φ ⊼ ( χ ⊼ ψ ) ) ↔ ¬ ( φ ∧ ( χ ⊼ ψ ) ) )", ref="df-nan", note="df-nan")
    s13 = lb.ref("s13", "( ( φ → ( χ ∧ ψ ) ) ↔ ¬ ( φ ∧ ¬ ( χ ∧ ψ ) ) )", ref="iman", note="iman")
    s14 = lb.ref("s14", "( ( φ ⊼ ( χ ⊼ ψ ) ) ↔ ( φ → ( χ ∧ ψ ) ) )", s11, s12, s13, ref="3bitr4i", note="3bitr4i")
    s15 = lb.ref("s15", "( ( ( τ ⊼ ( τ ⊼ τ ) ) ⊼ ( ( θ ⊼ χ ) ⊼ ( ( φ ⊼ θ ) ⊼ ( φ ⊼ θ ) ) ) ) ↔ ¬ ( ( τ ⊼ ( τ ⊼ τ ) ) ∧ ( ( θ ⊼ χ ) ⊼ ( ( φ ⊼ θ ) ⊼ ( φ ⊼ θ ) ) ) ) )", ref="df-nan", note="df-nan")
    s16 = lb.ref("s16", "( ( τ ⊼ τ ) ↔ ¬ ( τ ∧ τ ) )", ref="df-nan", note="df-nan")
    s17 = lb.ref("s17", "( ( τ ∧ ( τ ⊼ τ ) ) ↔ ( τ ∧ ¬ ( τ ∧ τ ) ) )", s16, ref="anbi2i", note="anbi2i")
    s18 = lb.ref("s18", "( ¬ ( τ ∧ ( τ ⊼ τ ) ) ↔ ¬ ( τ ∧ ¬ ( τ ∧ τ ) ) )", s17, ref="notbii", note="notbii")
    s19 = lb.ref("s19", "( ( τ ⊼ ( τ ⊼ τ ) ) ↔ ¬ ( τ ∧ ( τ ⊼ τ ) ) )", ref="df-nan", note="df-nan")
    s20 = lb.ref("s20", "( ( τ → ( τ ∧ τ ) ) ↔ ¬ ( τ ∧ ¬ ( τ ∧ τ ) ) )", ref="iman", note="iman")
    s21 = lb.ref("s21", "( ( τ ⊼ ( τ ⊼ τ ) ) ↔ ( τ → ( τ ∧ τ ) ) )", s18, s19, s20, ref="3bitr4i", note="3bitr4i")
    s22 = lb.ref("s22", "( ( θ ⊼ χ ) ↔ ¬ ( θ ∧ χ ) )", ref="df-nan", note="df-nan")
    s23 = lb.ref("s23", "( ( θ → ¬ χ ) ↔ ¬ ( θ ∧ χ ) )", ref="imnan", note="imnan")
    s24 = lb.ref("s24", "( ( θ ⊼ χ ) ↔ ( θ → ¬ χ ) )", s22, s23, ref="bitr4i", note="bitr4i")
    s25 = lb.ref("s25", "( ( ( φ ⊼ θ ) ⊼ ( φ ⊼ θ ) ) ↔ ¬ ( ( φ ⊼ θ ) ∧ ( φ ⊼ θ ) ) )", ref="df-nan", note="df-nan")
    s26 = lb.ref("s26", "( ( ( φ ⊼ θ ) ∧ ( φ ⊼ θ ) ) ↔ ( φ ⊼ θ ) )", ref="anidm", note="anidm")
    s27 = lb.ref("s27", "( ( φ ⊼ θ ) ↔ ¬ ( φ ∧ θ ) )", ref="df-nan", note="df-nan")
    s28 = lb.ref("s28", "( ( φ → ¬ θ ) ↔ ¬ ( φ ∧ θ ) )", ref="imnan", note="imnan")
    s29 = lb.ref("s29", "( ( φ → ¬ θ ) ↔ ( θ → ¬ φ ) )", ref="con2b", note="con2b")
    s30 = lb.ref("s30", "( ¬ ( φ ∧ θ ) ↔ ( θ → ¬ φ ) )", s28, s29, ref="bitr3i", note="bitr3i")
    s31 = lb.ref("s31", "( ( ( φ ⊼ θ ) ∧ ( φ ⊼ θ ) ) ↔ ( θ → ¬ φ ) )", s26, s27, s30, ref="3bitri", note="3bitri")
    s32 = lb.ref("s32", "( ( ( φ ⊼ θ ) ⊼ ( φ ⊼ θ ) ) ↔ ¬ ( θ → ¬ φ ) )", s25, s31, ref="xchbinx", note="xchbinx")
    s33 = lb.ref("s33", "( ( ( θ ⊼ χ ) ∧ ( ( φ ⊼ θ ) ⊼ ( φ ⊼ θ ) ) ) ↔ ( ( θ → ¬ χ ) ∧ ¬ ( θ → ¬ φ ) ) )", s24, s32, ref="anbi12i", note="anbi12i")
    s34 = lb.ref("s34", "( ¬ ( ( θ ⊼ χ ) ∧ ( ( φ ⊼ θ ) ⊼ ( φ ⊼ θ ) ) ) ↔ ¬ ( ( θ → ¬ χ ) ∧ ¬ ( θ → ¬ φ ) ) )", s33, ref="notbii", note="notbii")
    s35 = lb.ref("s35", "( ( ( θ ⊼ χ ) ⊼ ( ( φ ⊼ θ ) ⊼ ( φ ⊼ θ ) ) ) ↔ ¬ ( ( θ ⊼ χ ) ∧ ( ( φ ⊼ θ ) ⊼ ( φ ⊼ θ ) ) ) )", ref="df-nan", note="df-nan")
    s36 = lb.ref("s36", "( ( ( θ → ¬ χ ) → ( θ → ¬ φ ) ) ↔ ¬ ( ( θ → ¬ χ ) ∧ ¬ ( θ → ¬ φ ) ) )", ref="iman", note="iman")
    s37 = lb.ref("s37", "( ( ( θ ⊼ χ ) ⊼ ( ( φ ⊼ θ ) ⊼ ( φ ⊼ θ ) ) ) ↔ ( ( θ → ¬ χ ) → ( θ → ¬ φ ) ) )", s34, s35, s36, ref="3bitr4i", note="3bitr4i")
    s38 = lb.ref("s38", "( ( ( τ ⊼ ( τ ⊼ τ ) ) ∧ ( ( θ ⊼ χ ) ⊼ ( ( φ ⊼ θ ) ⊼ ( φ ⊼ θ ) ) ) ) ↔ ( ( τ → ( τ ∧ τ ) ) ∧ ( ( θ → ¬ χ ) → ( θ → ¬ φ ) ) ) )", s21, s37, ref="anbi12i", note="anbi12i")
    s39 = lb.ref("s39", "( ( ( τ ⊼ ( τ ⊼ τ ) ) ⊼ ( ( θ ⊼ χ ) ⊼ ( ( φ ⊼ θ ) ⊼ ( φ ⊼ θ ) ) ) ) ↔ ¬ ( ( τ → ( τ ∧ τ ) ) ∧ ( ( θ → ¬ χ ) → ( θ → ¬ φ ) ) ) )", s15, s38, ref="xchbinx", note="xchbinx")
    s40 = lb.ref("s40", "( ( ( φ ⊼ ( χ ⊼ ψ ) ) ∧ ( ( τ ⊼ ( τ ⊼ τ ) ) ⊼ ( ( θ ⊼ χ ) ⊼ ( ( φ ⊼ θ ) ⊼ ( φ ⊼ θ ) ) ) ) ) ↔ ( ( φ → ( χ ∧ ψ ) ) ∧ ¬ ( ( τ → ( τ ∧ τ ) ) ∧ ( ( θ → ¬ χ ) → ( θ → ¬ φ ) ) ) ) )", s14, s39, ref="anbi12i", note="anbi12i")
    s41 = lb.ref("s41", "( ¬ ( ( φ ⊼ ( χ ⊼ ψ ) ) ∧ ( ( τ ⊼ ( τ ⊼ τ ) ) ⊼ ( ( θ ⊼ χ ) ⊼ ( ( φ ⊼ θ ) ⊼ ( φ ⊼ θ ) ) ) ) ) ↔ ¬ ( ( φ → ( χ ∧ ψ ) ) ∧ ¬ ( ( τ → ( τ ∧ τ ) ) ∧ ( ( θ → ¬ χ ) → ( θ → ¬ φ ) ) ) ) )", s40, ref="notbii", note="notbii")
    s42 = lb.ref("s42", "( ( ( φ → ( χ ∧ ψ ) ) → ( ( τ → ( τ ∧ τ ) ) ∧ ( ( θ → ¬ χ ) → ( θ → ¬ φ ) ) ) ) ↔ ¬ ( ( φ → ( χ ∧ ψ ) ) ∧ ¬ ( ( τ → ( τ ∧ τ ) ) ∧ ( ( θ → ¬ χ ) → ( θ → ¬ φ ) ) ) ) )", ref="iman", note="iman")
    s43 = lb.ref("s43", "( ¬ ( ( φ ⊼ ( χ ⊼ ψ ) ) ∧ ( ( τ ⊼ ( τ ⊼ τ ) ) ⊼ ( ( θ ⊼ χ ) ⊼ ( ( φ ⊼ θ ) ⊼ ( φ ⊼ θ ) ) ) ) ) ↔ ( ( φ → ( χ ∧ ψ ) ) → ( ( τ → ( τ ∧ τ ) ) ∧ ( ( θ → ¬ χ ) → ( θ → ¬ φ ) ) ) ) )", s41, s42, ref="bitr4i", note="bitr4i")
    s44 = lb.ref("s44", "¬ ( ( φ ⊼ ( χ ⊼ ψ ) ) ∧ ( ( τ ⊼ ( τ ⊼ τ ) ) ⊼ ( ( θ ⊼ χ ) ⊼ ( ( φ ⊼ θ ) ⊼ ( φ ⊼ θ ) ) ) ) )", s8, s43, ref="mpbir", note="mpbir")
    s45 = lb.ref("s45", "( ( ( φ ⊼ ( χ ⊼ ψ ) ) ⊼ ( ( τ ⊼ ( τ ⊼ τ ) ) ⊼ ( ( θ ⊼ χ ) ⊼ ( ( φ ⊼ θ ) ⊼ ( φ ⊼ θ ) ) ) ) ) ↔ ¬ ( ( φ ⊼ ( χ ⊼ ψ ) ) ∧ ( ( τ ⊼ ( τ ⊼ τ ) ) ⊼ ( ( θ ⊼ χ ) ⊼ ( ( φ ⊼ θ ) ⊼ ( φ ⊼ θ ) ) ) ) ) )", ref="df-nan", note="df-nan")
    res = lb.ref("res", "( ( φ ⊼ ( χ ⊼ ψ ) ) ⊼ ( ( τ ⊼ ( τ ⊼ τ ) ) ⊼ ( ( θ ⊼ χ ) ⊼ ( ( φ ⊼ θ ) ⊼ ( φ ⊼ θ ) ) ) ) )", s44, s45, ref="mpbir", note="mpbir")
    return lb.build(res)

def prove_nic_imp(sys: System) -> Proof:
    """Inference for ~ nic-mp using ~ nic-ax as major premise.  (Contributed by
    Jeff Hoffman, 17-Nov-2007.)  (Proof modification is discouraged.)
    (New usage is discouraged.)
    """
    lb = ProofBuilder(sys, "nic-imp")
    h1 = lb.hyp("nic-imp.1", "( φ ⊼ ( χ ⊼ ψ ) )")
    s1 = lb.ref("s1", "( ( φ ⊼ ( χ ⊼ ψ ) ) ⊼ ( ( τ ⊼ ( τ ⊼ τ ) ) ⊼ ( ( θ ⊼ χ ) ⊼ ( ( φ ⊼ θ ) ⊼ ( φ ⊼ θ ) ) ) ) )", ref="nic-ax", note="nic-ax")
    res = lb.ref("res", "( ( θ ⊼ χ ) ⊼ ( ( φ ⊼ θ ) ⊼ ( φ ⊼ θ ) ) )", h1, s1, ref="nic-mp", note="nic-mp")
    return lb.build(res)

def prove_nic_idlem1(sys: System) -> Proof:
    """Lemma for ~ nic-id .  (Contributed by Jeff Hoffman, 17-Nov-2007.)
    (Proof modification is discouraged.)  (New usage is discouraged.)
    """
    lb = ProofBuilder(sys, "nic-idlem1")
    s1 = lb.ref("s1", "( ( φ ⊼ ( χ ⊼ ψ ) ) ⊼ ( ( τ ⊼ ( τ ⊼ τ ) ) ⊼ ( ( φ ⊼ χ ) ⊼ ( ( φ ⊼ φ ) ⊼ ( φ ⊼ φ ) ) ) ) )", ref="nic-ax", note="nic-ax")
    res = lb.ref("res", "( ( θ ⊼ ( τ ⊼ ( τ ⊼ τ ) ) ) ⊼ ( ( ( φ ⊼ ( χ ⊼ ψ ) ) ⊼ θ ) ⊼ ( ( φ ⊼ ( χ ⊼ ψ ) ) ⊼ θ ) ) )", s1, ref="nic-imp", note="nic-imp")
    return lb.build(res)

def prove_nic_idlem2(sys: System) -> Proof:
    """Lemma for ~ nic-id .  Inference used by ~ nic-id .  (Contributed by Jeff
    Hoffman, 17-Nov-2007.)  (Proof modification is discouraged.)
    (New usage is discouraged.)
    """
    lb = ProofBuilder(sys, "nic-idlem2")
    h1 = lb.hyp("nic-idlem2.1", "( η ⊼ ( ( φ ⊼ ( χ ⊼ ψ ) ) ⊼ θ ) )")
    s1 = lb.ref("s1", "( ( φ ⊼ ( χ ⊼ ψ ) ) ⊼ ( ( τ ⊼ ( τ ⊼ τ ) ) ⊼ ( ( φ ⊼ χ ) ⊼ ( ( φ ⊼ φ ) ⊼ ( φ ⊼ φ ) ) ) ) )", ref="nic-ax", note="nic-ax")
    s2 = lb.ref("s2", "( ( θ ⊼ ( τ ⊼ ( τ ⊼ τ ) ) ) ⊼ ( ( ( φ ⊼ ( χ ⊼ ψ ) ) ⊼ θ ) ⊼ ( ( φ ⊼ ( χ ⊼ ψ ) ) ⊼ θ ) ) )", s1, ref="nic-imp", note="nic-imp")
    s3 = lb.ref("s3", "( ( η ⊼ ( ( φ ⊼ ( χ ⊼ ψ ) ) ⊼ θ ) ) ⊼ ( ( ( θ ⊼ ( τ ⊼ ( τ ⊼ τ ) ) ) ⊼ η ) ⊼ ( ( θ ⊼ ( τ ⊼ ( τ ⊼ τ ) ) ) ⊼ η ) ) )", s2, ref="nic-imp", note="nic-imp")
    res = lb.ref("res", "( ( θ ⊼ ( τ ⊼ ( τ ⊼ τ ) ) ) ⊼ η )", h1, s3, ref="nic-mp", note="nic-mp")
    return lb.build(res)

def prove_nic_id(sys: System) -> Proof:
    """Theorem ~ id expressed with ` -/\\ ` .  (Contributed by Jeff Hoffman,
    17-Nov-2007.)  (Proof modification is discouraged.)
    (New usage is discouraged.)
    """
    lb = ProofBuilder(sys, "nic-id")
    s1 = lb.ref("s1", "( ( ψ ⊼ ( ψ ⊼ ψ ) ) ⊼ ( ( θ ⊼ ( θ ⊼ θ ) ) ⊼ ( ( φ ⊼ ψ ) ⊼ ( ( ψ ⊼ φ ) ⊼ ( ψ ⊼ φ ) ) ) ) )", ref="nic-ax", note="nic-ax")
    s2 = lb.ref("s2", "( ( ( ( φ ⊼ ψ ) ⊼ ( ( ψ ⊼ φ ) ⊼ ( ψ ⊼ φ ) ) ) ⊼ ( χ ⊼ ( χ ⊼ χ ) ) ) ⊼ ( ψ ⊼ ( ψ ⊼ ψ ) ) )", s1, ref="nic-idlem2", note="nic-idlem2")
    s3 = lb.ref("s3", "( ( ( χ ⊼ ( χ ⊼ χ ) ) ⊼ ( τ ⊼ ( τ ⊼ τ ) ) ) ⊼ ( ( ( ( φ ⊼ ψ ) ⊼ ( ( ψ ⊼ φ ) ⊼ ( ψ ⊼ φ ) ) ) ⊼ ( χ ⊼ ( χ ⊼ χ ) ) ) ⊼ ( ( ( φ ⊼ ψ ) ⊼ ( ( ψ ⊼ φ ) ⊼ ( ψ ⊼ φ ) ) ) ⊼ ( χ ⊼ ( χ ⊼ χ ) ) ) ) )", ref="nic-idlem1", note="nic-idlem1")
    s4 = lb.ref("s4", "( ( ( ( ( φ ⊼ ψ ) ⊼ ( ( ψ ⊼ φ ) ⊼ ( ψ ⊼ φ ) ) ) ⊼ ( χ ⊼ ( χ ⊼ χ ) ) ) ⊼ ( ψ ⊼ ( ψ ⊼ ψ ) ) ) ⊼ ( ( χ ⊼ ( χ ⊼ χ ) ) ⊼ ( τ ⊼ ( τ ⊼ τ ) ) ) )", s3, ref="nic-idlem2", note="nic-idlem2")
    res = lb.ref("res", "( τ ⊼ ( τ ⊼ τ ) )", s2, s4, ref="nic-mp", note="nic-mp")
    return lb.build(res)

def prove_nic_swap(sys: System) -> Proof:
    """The connector ` -/\\ ` is symmetric.  (Contributed by Jeff Hoffman,
    17-Nov-2007.)  (Proof modification is discouraged.)
    (New usage is discouraged.)
    """
    lb = ProofBuilder(sys, "nic-swap")
    s1 = lb.ref("s1", "( φ ⊼ ( φ ⊼ φ ) )", ref="nic-id", note="nic-id")
    s2 = lb.ref("s2", "( ( φ ⊼ ( φ ⊼ φ ) ) ⊼ ( ( τ ⊼ ( τ ⊼ τ ) ) ⊼ ( ( θ ⊼ φ ) ⊼ ( ( φ ⊼ θ ) ⊼ ( φ ⊼ θ ) ) ) ) )", ref="nic-ax", note="nic-ax")
    res = lb.ref("res", "( ( θ ⊼ φ ) ⊼ ( ( φ ⊼ θ ) ⊼ ( φ ⊼ θ ) ) )", s1, s2, ref="nic-mp", note="nic-mp")
    return lb.build(res)

def prove_nic_isw1(sys: System) -> Proof:
    """Inference version of ~ nic-swap .  (Contributed by Jeff Hoffman,
    17-Nov-2007.)  (Proof modification is discouraged.)
    (New usage is discouraged.)
    """
    lb = ProofBuilder(sys, "nic-isw1")
    h1 = lb.hyp("nic-isw1.1", "( θ ⊼ φ )")
    s1 = lb.ref("s1", "( ( θ ⊼ φ ) ⊼ ( ( φ ⊼ θ ) ⊼ ( φ ⊼ θ ) ) )", ref="nic-swap", note="nic-swap")
    res = lb.ref("res", "( φ ⊼ θ )", h1, s1, ref="nic-mp", note="nic-mp")
    return lb.build(res)

def prove_nic_isw2(sys: System) -> Proof:
    """Inference for swapping nested terms.  (Contributed by Jeff Hoffman,
    17-Nov-2007.)  (Proof modification is discouraged.)
    (New usage is discouraged.)
    """
    lb = ProofBuilder(sys, "nic-isw2")
    h1 = lb.hyp("nic-isw2.1", "( ψ ⊼ ( θ ⊼ φ ) )")
    s1 = lb.ref("s1", "( ( φ ⊼ θ ) ⊼ ( ( θ ⊼ φ ) ⊼ ( θ ⊼ φ ) ) )", ref="nic-swap", note="nic-swap")
    s2 = lb.ref("s2", "( ( ψ ⊼ ( θ ⊼ φ ) ) ⊼ ( ( ( φ ⊼ θ ) ⊼ ψ ) ⊼ ( ( φ ⊼ θ ) ⊼ ψ ) ) )", s1, ref="nic-imp", note="nic-imp")
    s3 = lb.ref("s3", "( ( φ ⊼ θ ) ⊼ ψ )", h1, s2, ref="nic-mp", note="nic-mp")
    res = lb.ref("res", "( ψ ⊼ ( φ ⊼ θ ) )", s3, ref="nic-isw1", note="nic-isw1")
    return lb.build(res)

def prove_nic_iimp1(sys: System) -> Proof:
    """Inference version of ~ nic-imp using right-handed term.  (Contributed by
    Jeff Hoffman, 17-Nov-2007.)  (Proof modification is discouraged.)
    (New usage is discouraged.)
    """
    lb = ProofBuilder(sys, "nic-iimp1")
    h1 = lb.hyp("nic-iimp1.1", "( φ ⊼ ( χ ⊼ ψ ) )")
    h2 = lb.hyp("nic-iimp1.2", "( θ ⊼ χ )")
    s1 = lb.ref("s1", "( ( θ ⊼ χ ) ⊼ ( ( φ ⊼ θ ) ⊼ ( φ ⊼ θ ) ) )", h1, ref="nic-imp", note="nic-imp")
    s2 = lb.ref("s2", "( φ ⊼ θ )", h2, s1, ref="nic-mp", note="nic-mp")
    res = lb.ref("res", "( θ ⊼ φ )", s2, ref="nic-isw1", note="nic-isw1")
    return lb.build(res)

def prove_nic_iimp2(sys: System) -> Proof:
    """Inference version of ~ nic-imp using left-handed term.  (Contributed by
    Jeff Hoffman, 17-Nov-2007.)  (Proof modification is discouraged.)
    (New usage is discouraged.)
    """
    lb = ProofBuilder(sys, "nic-iimp2")
    h1 = lb.hyp("nic-iimp2.1", "( ( φ ⊼ ψ ) ⊼ ( χ ⊼ χ ) )")
    h2 = lb.hyp("nic-iimp2.2", "( θ ⊼ φ )")
    s1 = lb.ref("s1", "( ( χ ⊼ χ ) ⊼ ( φ ⊼ ψ ) )", h1, ref="nic-isw1", note="nic-isw1")
    res = lb.ref("res", "( θ ⊼ ( χ ⊼ χ ) )", s1, h2, ref="nic-iimp1", note="nic-iimp1")
    return lb.build(res)

def prove_nic_idel(sys: System) -> Proof:
    """Inference to remove the trailing term.  (Contributed by Jeff Hoffman,
    17-Nov-2007.)  (Proof modification is discouraged.)
    (New usage is discouraged.)
    """
    lb = ProofBuilder(sys, "nic-idel")
    h1 = lb.hyp("nic-idel.1", "( φ ⊼ ( χ ⊼ ψ ) )")
    s1 = lb.ref("s1", "( χ ⊼ ( χ ⊼ χ ) )", ref="nic-id", note="nic-id")
    s2 = lb.ref("s2", "( ( χ ⊼ χ ) ⊼ χ )", s1, ref="nic-isw1", note="nic-isw1")
    s3 = lb.ref("s3", "( ( ( χ ⊼ χ ) ⊼ χ ) ⊼ ( ( φ ⊼ ( χ ⊼ χ ) ) ⊼ ( φ ⊼ ( χ ⊼ χ ) ) ) )", h1, ref="nic-imp", note="nic-imp")
    res = lb.ref("res", "( φ ⊼ ( χ ⊼ χ ) )", s2, s3, ref="nic-mp", note="nic-mp")
    return lb.build(res)

def prove_nic_ich(sys: System) -> Proof:
    """Chained inference.  (Contributed by Jeff Hoffman, 17-Nov-2007.)
    (Proof modification is discouraged.)  (New usage is discouraged.)
    """
    lb = ProofBuilder(sys, "nic-ich")
    h1 = lb.hyp("nic-ich.1", "( φ ⊼ ( ψ ⊼ ψ ) )")
    h2 = lb.hyp("nic-ich.2", "( ψ ⊼ ( χ ⊼ χ ) )")
    s1 = lb.ref("s1", "( ( χ ⊼ χ ) ⊼ ψ )", h2, ref="nic-isw1", note="nic-isw1")
    s2 = lb.ref("s2", "( ( ( χ ⊼ χ ) ⊼ ψ ) ⊼ ( ( φ ⊼ ( χ ⊼ χ ) ) ⊼ ( φ ⊼ ( χ ⊼ χ ) ) ) )", h1, ref="nic-imp", note="nic-imp")
    res = lb.ref("res", "( φ ⊼ ( χ ⊼ χ ) )", s1, s2, ref="nic-mp", note="nic-mp")
    return lb.build(res)

def prove_nic_idbl(sys: System) -> Proof:
    """Double the terms.  Since doubling is the same as negation, this can be
    viewed as a contraposition inference.  (Contributed by Jeff Hoffman,
    17-Nov-2007.)  (Proof modification is discouraged.)
    (New usage is discouraged.)
    """
    lb = ProofBuilder(sys, "nic-idbl")
    h1 = lb.hyp("nic-idbl.1", "( φ ⊼ ( ψ ⊼ ψ ) )")
    s1 = lb.ref("s1", "( ( ψ ⊼ ψ ) ⊼ ( ( φ ⊼ ψ ) ⊼ ( φ ⊼ ψ ) ) )", h1, ref="nic-imp", note="nic-imp")
    s2 = lb.ref("s2", "( ( φ ⊼ ψ ) ⊼ ( ( φ ⊼ φ ) ⊼ ( φ ⊼ φ ) ) )", h1, ref="nic-imp", note="nic-imp")
    res = lb.ref("res", "( ( ψ ⊼ ψ ) ⊼ ( ( φ ⊼ φ ) ⊼ ( φ ⊼ φ ) ) )", s1, s2, ref="nic-ich", note="nic-ich")
    return lb.build(res)

def prove_nic_bijust(sys: System) -> Proof:
    """Biconditional justification from Nicod's axiom.  For nic-* definitions,
    the biconditional connective is not used.  Instead, definitions are made
    based on this form. ~ nic-bi1 and ~ nic-bi2 are used to convert the
    definitions into usable theorems about one side of the implication.
    (Contributed by Jeff Hoffman, 18-Nov-2007.)
    (Proof modification is discouraged.)  (New usage is discouraged.)
    """
    lb = ProofBuilder(sys, "nic-bijust")
    res = lb.ref("res", "( ( τ ⊼ τ ) ⊼ ( ( τ ⊼ τ ) ⊼ ( τ ⊼ τ ) ) )", ref="nic-swap", note="nic-swap")
    return lb.build(res)

def prove_nic_bi1(sys: System) -> Proof:
    """Inference to extract one side of an implication from a definition.
    (Contributed by Jeff Hoffman, 18-Nov-2007.)
    (Proof modification is discouraged.)  (New usage is discouraged.)
    """
    lb = ProofBuilder(sys, "nic-bi1")
    h1 = lb.hyp("nic-bi1.1", "( ( φ ⊼ ψ ) ⊼ ( ( φ ⊼ φ ) ⊼ ( ψ ⊼ ψ ) ) )")
    s1 = lb.ref("s1", "( φ ⊼ ( φ ⊼ φ ) )", ref="nic-id", note="nic-id")
    s2 = lb.ref("s2", "( φ ⊼ ( φ ⊼ ψ ) )", h1, s1, ref="nic-iimp1", note="nic-iimp1")
    s3 = lb.ref("s3", "( φ ⊼ ( ψ ⊼ φ ) )", s2, ref="nic-isw2", note="nic-isw2")
    res = lb.ref("res", "( φ ⊼ ( ψ ⊼ ψ ) )", s3, ref="nic-idel", note="nic-idel")
    return lb.build(res)

def prove_nic_bi2(sys: System) -> Proof:
    """Inference to extract the other side of an implication from a
    'biconditional' definition.  (Contributed by Jeff Hoffman, 18-Nov-2007.)
    (Proof modification is discouraged.)  (New usage is discouraged.)
    """
    lb = ProofBuilder(sys, "nic-bi2")
    h1 = lb.hyp("nic-bi2.1", "( ( φ ⊼ ψ ) ⊼ ( ( φ ⊼ φ ) ⊼ ( ψ ⊼ ψ ) ) )")
    s1 = lb.ref("s1", "( ( φ ⊼ ψ ) ⊼ ( ( ψ ⊼ ψ ) ⊼ ( φ ⊼ φ ) ) )", h1, ref="nic-isw2", note="nic-isw2")
    s2 = lb.ref("s2", "( ψ ⊼ ( ψ ⊼ ψ ) )", ref="nic-id", note="nic-id")
    s3 = lb.ref("s3", "( ψ ⊼ ( φ ⊼ ψ ) )", s1, s2, ref="nic-iimp1", note="nic-iimp1")
    res = lb.ref("res", "( ψ ⊼ ( φ ⊼ φ ) )", s3, ref="nic-idel", note="nic-idel")
    return lb.build(res)

def prove_nic_stdmp(sys: System) -> Proof:
    """Derive the standard modus ponens from ~ nic-mp .  (Contributed by Jeff
    Hoffman, 18-Nov-2007.)  (Proof modification is discouraged.)
    (New usage is discouraged.)
    """
    lb = ProofBuilder(sys, "nic-stdmp")
    h1 = lb.hyp("nic-smin", "φ")
    h2 = lb.hyp("nic-smaj", "( φ → ψ )")
    s1 = lb.ref("s1", "( ( ( φ ⊼ ( ψ ⊼ ψ ) ) ⊼ ( φ → ψ ) ) ⊼ ( ( ( φ ⊼ ( ψ ⊼ ψ ) ) ⊼ ( φ ⊼ ( ψ ⊼ ψ ) ) ) ⊼ ( ( φ → ψ ) ⊼ ( φ → ψ ) ) ) )", ref="nic-dfim", note="nic-dfim")
    s2 = lb.ref("s2", "( ( φ → ψ ) ⊼ ( ( φ ⊼ ( ψ ⊼ ψ ) ) ⊼ ( φ ⊼ ( ψ ⊼ ψ ) ) ) )", s1, ref="nic-bi2", note="nic-bi2")
    s3 = lb.ref("s3", "( φ ⊼ ( ψ ⊼ ψ ) )", h2, s2, ref="nic-mp", note="nic-mp")
    res = lb.ref("res", "ψ", h1, s3, ref="nic-mp", note="nic-mp")
    return lb.build(res)

def prove_nic_luk1(sys: System) -> Proof:
    """Proof of ~ luk-1 from ~ nic-ax and ~ nic-mp (and Definitions ~ nic-dfim
    and ~ nic-dfneg ).  Note that the standard axioms ~ ax-1 , ~ ax-2 , and
    ~ ax-3 are proved from the Lukasiewicz axioms by Theorems ~ ax1 , ~ ax2 ,
    and ~ ax3 .  (Contributed by Jeff Hoffman, 18-Nov-2007.)
    (Proof modification is discouraged.)  (New usage is discouraged.)
    """
    lb = ProofBuilder(sys, "nic-luk1")
    s1 = lb.ref("s1", "( ( ( φ ⊼ ( ψ ⊼ ψ ) ) ⊼ ( φ → ψ ) ) ⊼ ( ( ( φ ⊼ ( ψ ⊼ ψ ) ) ⊼ ( φ ⊼ ( ψ ⊼ ψ ) ) ) ⊼ ( ( φ → ψ ) ⊼ ( φ → ψ ) ) ) )", ref="nic-dfim", note="nic-dfim")
