def prove_nic_luk2(sys: System) -> Proof:
    """Proof of ~ luk-2 from ~ nic-ax and ~ nic-mp .  (Contributed by Jeff
    Hoffman, 18-Nov-2007.)  (Proof modification is discouraged.)
    (New usage is discouraged.)
    """
    lb = ProofBuilder(sys, "nic-luk2")
    s1 = lb.ref("s1", "( ( ( ( ¬ φ ) ⊼ ( φ ⊼ φ ) ) ⊼ ( ¬ φ → φ ) ) ⊼ ( ( ( ( ¬ φ ) ⊼ ( φ ⊼ φ ) ) ⊼ ( ( ¬ φ ) ⊼ ( φ ⊼ φ ) ) ) ⊼ ( ( ¬ φ → φ ) ⊼ ( ¬ φ → φ ) ) ) )", ref="nic-dfim", note="nic-dfim")
