    s3 = lb.ref("s3", "( ( ( φ ⊼ φ ) ⊼ ( ¬ φ ) ) ⊼ ( ( ( φ ⊼ φ ) ⊼ ( φ ⊼ φ ) ) ⊼ ( ( ¬ φ ) ⊼ ( ¬ φ ) ) ) )", ref="nic-dfneg", note="nic-dfneg")
    s4 = lb.ref("s4", "( ( φ ⊼ φ ) ⊼ ( ( φ ⊼ φ ) ⊼ ( φ ⊼ φ ) ) )", ref="nic-id", note="nic-id")
    s5 = lb.ref("s5", "( ( φ ⊼ φ ) ⊼ ( ( φ ⊼ φ ) ⊼ ( ¬ φ ) ) )", s3, s4, ref="nic-iimp1", note="nic-iimp1")
    s6 = lb.ref("s6", "( ( φ ⊼ φ ) ⊼ ( ( ¬ φ ) ⊼ ( φ ⊼ φ ) ) )", s5, ref="nic-isw2", note="nic-isw2")
    s7 = lb.ref("s7", "( ( φ ⊼ φ ) ⊼ ( ¬ φ → φ ) )", s2, s6, ref="nic-iimp1", note="nic-iimp1")
    s8 = lb.ref("s8", "( ( ¬ φ → φ ) ⊼ ( φ ⊼ φ ) )", s7, ref="nic-isw1", note="nic-isw1")
    s9 = lb.ref("s9", "( ( ( ( ¬ φ → φ ) ⊼ ( φ ⊼ φ ) ) ⊼ ( ( ¬ φ → φ ) → φ ) ) ⊼ ( ( ( ( ¬ φ → φ ) ⊼ ( φ ⊼ φ ) ) ⊼ ( ( ¬ φ → φ ) ⊼ ( φ ⊼ φ ) ) ) ⊼ ( ( ( ¬ φ → φ ) → φ ) ⊼ ( ( ¬ φ → φ ) → φ ) ) ) )", ref="nic-dfim", note="nic-dfim")
    s10 = lb.ref("s10", "( ( ( ¬ φ → φ ) ⊼ ( φ ⊼ φ ) ) ⊼ ( ( ( ¬ φ → φ ) → φ ) ⊼ ( ( ¬ φ → φ ) → φ ) ) )", s9, ref="nic-bi1", note="nic-bi1")
