    s9 = lb.ref("s9", "( ( ( ( φ → ⊥ ) → ψ ) → ( ( ψ → ( ( ψ → ⊥ ) → ⊥ ) ) → ( ( φ → ⊥ ) → ( ( ψ → ⊥ ) → ⊥ ) ) ) ) → ( ( ψ → ( ( ψ → ⊥ ) → ⊥ ) ) → ( ( ( φ → ⊥ ) → ψ ) → ( ( φ → ⊥ ) → ( ( ψ → ⊥ ) → ⊥ ) ) ) ) )", ref="tbwlem1", note="tbwlem1")
