def prove_re1luk2(sys: System) -> Proof:
    """~ luk-2 derived from the Tarski-Bernays-Wajsberg axioms.  (Contributed by
    Anthony Hart, 16-Aug-2011.)  (Proof modification is discouraged.)
    (New usage is discouraged.)
    """
    lb = ProofBuilder(sys, "re1luk2")
    s1 = lb.ref("s1", "( ( ( ¬ φ → ( φ → ⊥ ) ) → ( ( ( φ → ⊥ ) → ¬ φ ) → ⊥ ) ) → ⊥ )", ref="tbw-negdf", note="tbw-negdf")
    s2 = lb.ref("s2", "( ( ( ( φ → ⊥ ) → ¬ φ ) → ⊥ ) → ( ( ¬ φ → ( φ → ⊥ ) ) → ( ( ( φ → ⊥ ) → ¬ φ ) → ⊥ ) ) )", ref="tbw-ax2", note="tbw-ax2")
    s3 = lb.ref("s3", "( ( ( ( ( φ → ⊥ ) → ¬ φ ) → ⊥ ) → ( ( ¬ φ → ( φ → ⊥ ) ) → ( ( ( φ → ⊥ ) → ¬ φ ) → ⊥ ) ) ) → ( ( ( ( ¬ φ → ( φ → ⊥ ) ) → ( ( ( φ → ⊥ ) → ¬ φ ) → ⊥ ) ) → ⊥ ) → ( ( φ → ⊥ ) → ¬ φ ) ) )", ref="tbwlem4", note="tbwlem4")
    s4 = lb.mp("s4", s2, s3, "ax-mp")
    s5 = lb.mp("s5", s1, s4, "ax-mp")
    s6 = lb.ref("s6", "( ( ( φ → ⊥ ) → ¬ φ ) → ( ( ¬ φ → φ ) → ( ( φ → ⊥ ) → φ ) ) )", ref="tbw-ax1", note="tbw-ax1")
    s7 = lb.mp("s7", s5, s6, "ax-mp")
    s8 = lb.ref("s8", "( ( ( φ → ⊥ ) → φ ) → φ )", ref="tbw-ax3", note="tbw-ax3")
    res = lb.ref("res", "( ( ¬ φ → φ ) → φ )", s7, s8, ref="tbwsyl", note="tbwsyl")
    return lb.build(res)

def prove_re1luk3(sys: System) -> Proof:
    """~ luk-3 derived from the Tarski-Bernays-Wajsberg axioms.

    This theorem, along with ~ re1luk1 and ~ re1luk2 proves that ~ tbw-ax1 ,
    ~ tbw-ax2 , ~ tbw-ax3 , and ~ tbw-ax4 , with ~ ax-mp can be used as a
    complete axiom system for all of propositional calculus.  (Contributed by
    Anthony Hart, 16-Aug-2011.)  (Proof modification is discouraged.)
    (New usage is discouraged.)
    """
    lb = ProofBuilder(sys, "re1luk3")
    s1 = lb.ref("s1", "( ⊥ → ψ )", ref="tbw-ax4", note="tbw-ax4")
    s2 = lb.ref("s2", "( ( φ → ⊥ ) → ( ( ⊥ → ψ ) → ( φ → ψ ) ) )", ref="tbw-ax1", note="tbw-ax1")
    s3 = lb.ref("s3", "( ( ( φ → ⊥ ) → ( ( ⊥ → ψ ) → ( φ → ψ ) ) ) → ( ( ⊥ → ψ ) → ( ( φ → ⊥ ) → ( φ → ψ ) ) ) )", ref="tbwlem1", note="tbwlem1")
    s4 = lb.mp("s4", s2, s3, "ax-mp")
    s5 = lb.mp("s5", s1, s4, "ax-mp")
    s6 = lb.ref("s6", "( ( ( φ → ⊥ ) → ( φ → ψ ) ) → ( φ → ( ( φ → ⊥ ) → ψ ) ) )", ref="tbwlem1", note="tbwlem1")
    s7 = lb.mp("s7", s5, s6, "ax-mp")
    s8 = lb.ref("s8", "( ( ( ¬ φ → ( φ → ⊥ ) ) → ( ( ( φ → ⊥ ) → ¬ φ ) → ⊥ ) ) → ⊥ )", ref="tbw-negdf", note="tbw-negdf")
    s9 = lb.ref("s9", "( ( ( ( ¬ φ → ( φ → ⊥ ) ) → ( ( ( φ → ⊥ ) → ¬ φ ) → ⊥ ) ) → ⊥ ) → ( ¬ φ → ( φ → ⊥ ) ) )", ref="tbwlem5", note="tbwlem5")
    s10 = lb.mp("s10", s8, s9, "ax-mp")
    s11 = lb.ref("s11", "( ( ¬ φ → ( φ → ⊥ ) ) → ( ( ( φ → ⊥ ) → ψ ) → ( ¬ φ → ψ ) ) )", ref="tbw-ax1", note="tbw-ax1")
    s12 = lb.mp("s12", s10, s11, "ax-mp")
    res = lb.ref("res", "( φ → ( ¬ φ → ψ ) )", s7, s12, ref="tbwsyl", note="tbwsyl")
    return lb.build(res)

def prove_merco1(sys: System) -> Proof:
    """A single axiom for propositional calculus discovered by C. A. Meredith.

    This axiom is worthy of note, due to it having only 19 symbols, not
    counting parentheses.  The more well-known ~ meredith has 21 symbols, sans
    parentheses.

    See ~ merco2 for another axiom of equal length.  (Contributed by Anthony
    Hart, 13-Aug-2011.)  (Proof modification is discouraged.)
    (New usage is discouraged.)
    """
    lb = ProofBuilder(sys, "merco1")
    s1 = lb.ref("s1", "( ¬ χ → ( ¬ θ → ¬ χ ) )", ref="ax-1", note="ax-1")
    s2 = lb.ref("s2", "( ⊥ → ( ¬ θ → ¬ χ ) )", ref="falim", note="falim")
    s3 = lb.ref("s3", "( ( χ → ⊥ ) → ( ¬ θ → ¬ χ ) )", s1, s2, ref="ja", note="ja")
    s4 = lb.ref("s4", "( ( ( φ → ψ ) → ( χ → ⊥ ) ) → ( ( φ → ψ ) → ( ¬ θ → ¬ χ ) ) )", s3, ref="imim2i", note="imim2i")
    s5 = lb.ref("s5", "( ( ( ( φ → ψ ) → ( ¬ θ → ¬ χ ) ) → θ ) → ( ( ( φ → ψ ) → ( χ → ⊥ ) ) → θ ) )", s4, ref="imim1i", note="imim1i")
    s6 = lb.ref("s6", "( ( ( ( ( φ → ψ ) → ( χ → ⊥ ) ) → θ ) → τ ) → ( ( ( ( φ → ψ ) → ( ¬ θ → ¬ χ ) ) → θ ) → τ ) )", s5, ref="imim1i", note="imim1i")
    s7 = lb.ref("s7", "( ( ( ( ( φ → ψ ) → ( ¬ θ → ¬ χ ) ) → θ ) → τ ) → ( ( τ → φ ) → ( χ → φ ) ) )", ref="meredith", note="meredith")
    res = lb.ref("res", "( ( ( ( ( φ → ψ ) → ( χ → ⊥ ) ) → θ ) → τ ) → ( ( τ → φ ) → ( χ → φ ) ) )", s6, s7, ref="syl", note="syl")
    return lb.build(res)

