    s16 = lb.mp("s16", s14, s15, "ax-mp")
    s17 = lb.ref("s17", "( ( ( ( ( ⊥ → χ ) → ( ( φ → ( φ → ( ⊥ → φ ) ) ) → ⊥ ) ) → ( ( φ → ( ⊥ → φ ) ) → ⊥ ) ) → ( φ → ( ⊥ → χ ) ) ) → ( ( ( φ → ( ⊥ → χ ) ) → ⊥ ) → ( ( φ → ( φ → ( ⊥ → φ ) ) ) → ⊥ ) ) )", ref="merco1", note="merco1")
    s18 = lb.ref("s18", "( ( ( ( ( ( ⊥ → χ ) → ( ( φ → ( φ → ( ⊥ → φ ) ) ) → ⊥ ) ) → ( ( φ → ( ⊥ → φ ) ) → ⊥ ) ) → ( φ → ( ⊥ → χ ) ) ) → ( ( ( φ → ( ⊥ → χ ) ) → ⊥ ) → ( ( φ → ( φ → ( ⊥ → φ ) ) ) → ⊥ ) ) ) → ( ( ( ( ( φ → ( ⊥ → χ ) ) → ⊥ ) → ( ( φ → ( φ → ( ⊥ → φ ) ) ) → ⊥ ) ) → ( ⊥ → χ ) ) → ( ( φ → ( ⊥ → φ ) ) → ( ⊥ → χ ) ) ) )", ref="merco1", note="merco1")
    s19 = lb.mp("s19", s17, s18, "ax-mp")
    s20 = lb.ref("s20", "( ( ( ( ( ( φ → ( ⊥ → χ ) ) → ⊥ ) → ( ( φ → ( φ → ( ⊥ → φ ) ) ) → ⊥ ) ) → ( ⊥ → χ ) ) → ( ( φ → ( ⊥ → φ ) ) → ( ⊥ → χ ) ) ) → ( ( ( ( φ → ( ⊥ → φ ) ) → ( ⊥ → χ ) ) → ( φ → ( ⊥ → χ ) ) ) → ( ( φ → ( φ → ( ⊥ → φ ) ) ) → ( φ → ( ⊥ → χ ) ) ) ) )", ref="merco1", note="merco1")
