def prove_merco2(sys: System) -> Proof:
    """A single axiom for propositional calculus discovered by C. A. Meredith.

    This axiom has 19 symbols, sans auxiliaries.  See notes in ~ merco1 .
    (Contributed by Anthony Hart, 7-Aug-2011.)
    (Proof modification is discouraged.)  (New usage is discouraged.)
    """
    lb = ProofBuilder(sys, "merco2")
    s1 = lb.ref("s1", "( ⊥ → χ )", ref="falim", note="falim")
    s2 = lb.ref("s2", "( ( ( φ → ψ ) → ( ( ⊥ → χ ) → θ ) ) → ( ( ⊥ → χ ) → ( ( φ → ψ ) → θ ) ) )", ref="pm2.04", note="pm2.04")
    s3 = lb.ref("s3", "( ( ( φ → ψ ) → ( ( ⊥ → χ ) → θ ) ) → ( ( φ → ψ ) → θ ) )", s1, s2, ref="mpi", note="mpi")
    s4 = lb.ref("s4", "( ( ( φ → ψ ) → θ ) → ( ¬ φ → θ ) )", ref="jarl", note="jarl")
    s5 = lb.ref("s5", "( ( ( φ → ψ ) → θ ) → ( θ → θ ) )", ref="idd", note="idd")
    s6 = lb.ref("s6", "( ( ( φ → ψ ) → θ ) → ( ( φ → θ ) → θ ) )", s4, s5, ref="jad", note="jad")
    s7 = lb.ref("s7", "( ( ( φ → θ ) → θ ) → ( ( θ → φ ) → φ ) )", ref="looinv", note="looinv")
    s8 = lb.ref("s8", "( ( ( φ → ψ ) → ( ( ⊥ → χ ) → θ ) ) → ( ( θ → φ ) → φ ) )", s3, s6, s7, ref="3syl", note="3syl")
    s9 = lb.ref("s9", "( ( ( φ → ψ ) → ( ( ⊥ → χ ) → θ ) ) → ( ( θ → φ ) → ( τ → φ ) ) )", s8, ref="a1dd", note="a1dd")
    s10 = lb.ref("s10", "( η → ( ( ( φ → ψ ) → ( ( ⊥ → χ ) → θ ) ) → ( ( θ → φ ) → ( τ → φ ) ) ) )", s9, ref="a1i", note="a1i")
    res = lb.ref("res", "( ( ( φ → ψ ) → ( ( ⊥ → χ ) → θ ) ) → ( ( θ → φ ) → ( τ → ( η → φ ) ) ) )", s10, ref="com4l", note="com4l")
    return lb.build(res)

