    lb = ProofBuilder(sys, "mercolem1")
    s1 = lb.ref("s1", "( ( ( φ → φ ) → ( ( ⊥ → φ ) → φ ) ) → ( ( φ → φ ) → ( φ → ( φ → φ ) ) ) )", ref="merco2", note="merco2")
    s2 = lb.ref("s2", "( ( ( φ → φ ) → ( ( ⊥ → φ ) → φ ) ) → ( ( φ → φ ) → ( φ → ( φ → φ ) ) ) )", ref="merco2", note="merco2")
    s3 = lb.ref("s3", "( ( ( χ → φ ) → ( ( ⊥ → φ ) → ( φ → ψ ) ) ) → ( ( ( φ → ψ ) → χ ) → ( ψ → ( θ → χ ) ) ) )", ref="merco2", note="merco2")
