    s8 = lb.mp("s8", s6, s7, "ax-mp")
    s9 = lb.ref("s9", "( ( ( ( ( ( φ → ψ ) → χ ) → ( ψ → ( θ → χ ) ) ) → ( ( ⊥ → φ ) → ( φ → ψ ) ) ) → ( ( ⊥ → φ ) → ( ( χ → φ ) → ( ( ⊥ → φ ) → ( φ → ψ ) ) ) ) ) → ( ( ( ( χ → φ ) → ( ( ⊥ → φ ) → ( φ → ψ ) ) ) → ( ( ( φ → ψ ) → χ ) → ( ψ → ( θ → χ ) ) ) ) → ( ( ( ( φ → φ ) → ( ( ⊥ → φ ) → φ ) ) → ( ( φ → φ ) → ( φ → ( φ → φ ) ) ) ) → ( ( ( ( φ → φ ) → ( ( ⊥ → φ ) → φ ) ) → ( ( φ → φ ) → ( φ → ( φ → φ ) ) ) ) → ( ( ( φ → ψ ) → χ ) → ( ψ → ( θ → χ ) ) ) ) ) ) )", ref="merco2", note="merco2")
    s10 = lb.mp("s10", s8, s9, "ax-mp")
