    s8 = lb.ref("s8", "( ( ( ( ψ → χ ) → ( ψ → ( φ → χ ) ) ) → ( ( ( ψ → ( φ → χ ) ) → ( ( ψ → χ ) → ( ( φ → ψ ) → ( ( ψ → χ ) → ( φ → χ ) ) ) ) ) → ( ( ( ψ → χ ) → ( ψ → ( φ → χ ) ) ) → ( ( φ → ψ ) → ( ( ψ → χ ) → ( ( φ → ψ ) → ( ( ψ → χ ) → ( φ → χ ) ) ) ) ) ) ) ) → ( ( ( ψ → ( φ → χ ) ) → ( ( ψ → χ ) → ( ( φ → ψ ) → ( ( ψ → χ ) → ( φ → χ ) ) ) ) ) → ( ( ( ψ → χ ) → ( ψ → ( φ → χ ) ) ) → ( ( φ → ψ ) → ( ( ψ → χ ) → ( ( φ → ψ ) → ( ( ψ → χ ) → ( φ → χ ) ) ) ) ) ) ) )", ref="mercolem6", note="mercolem6")
    s9 = lb.mp("s9", s7, s8, "ax-mp")
