    s13 = lb.mp("s13", s11, s12, "ax-mp")
    s14 = lb.ref("s14", "( ( ( ψ → χ ) → ( ( φ → ψ ) → ( ( ψ → χ ) → ( φ → χ ) ) ) ) → ( ( φ → ψ ) → ( ( ψ → χ ) → ( φ → χ ) ) ) )", ref="mercolem6", note="mercolem6")
    res = lb.mp("res", s13, s14, "ax-mp")
    return lb.build(res)

