    """~ tbw-ax2 rederived from ~ merco2 .  (Contributed by Anthony Hart,
    16-Aug-2011.)  (Proof modification is discouraged.)
    (New usage is discouraged.)
    """
    lb = ProofBuilder(sys, "re1tbw2")
