    s2 = lb.ref("s2", "( ( ( ( φ → φ ) → φ ) → ( φ → ( ψ → φ ) ) ) → ( φ → ( ψ → ( φ → ( ψ → φ ) ) ) ) )", ref="mercolem1", note="mercolem1")
    s3 = lb.mp("s3", s1, s2, "ax-mp")
