    s5 = lb.mp("s5", s3, s4, "ax-mp")
    s6 = lb.ref("s6", "( ( ψ → ( φ → ( ψ → φ ) ) ) → ( φ → ( ψ → φ ) ) )", ref="mercolem6", note="mercolem6")
