    s2 = lb.ref("s2", "( ( ( φ → ψ ) → φ ) → ( ( ( ( φ → φ ) → φ ) → ( φ → ( φ → φ ) ) ) → ( ( ( φ → ψ ) → φ ) → φ ) ) )", ref="mercolem2", note="mercolem2")
    s3 = lb.ref("s3", "( ( ( ( φ → ψ ) → φ ) → ( ( ( ( φ → φ ) → φ ) → ( φ → ( φ → φ ) ) ) → ( ( ( φ → ψ ) → φ ) → φ ) ) ) → ( ( ( ( φ → φ ) → φ ) → ( φ → ( φ → φ ) ) ) → ( ( ( φ → ψ ) → φ ) → φ ) ) )", ref="mercolem6", note="mercolem6")
