def prove_re1tbw4(sys: System) -> Proof:
    """~ tbw-ax4 rederived from ~ merco2 .

    This theorem, along with ~ re1tbw1 , ~ re1tbw2 , and ~ re1tbw3 , shows
    that ~ merco2 , along with ~ ax-mp , can be used as a complete
    axiomatization of propositional calculus.  (Contributed by Anthony Hart,
    16-Aug-2011.)  (Proof modification is discouraged.)
    (New usage is discouraged.)
    """
    lb = ProofBuilder(sys, "re1tbw4")
    s1 = lb.ref("s1", "( ( ( φ → φ ) → φ ) → φ )", ref="re1tbw3", note="re1tbw3")
    s2 = lb.ref("s2", "( φ → ( ( φ → φ ) → φ ) )", ref="re1tbw2", note="re1tbw2")
    s3 = lb.ref("s3", "( ( φ → ( ( φ → φ ) → φ ) ) → ( ( ( ( φ → φ ) → φ ) → φ ) → ( φ → φ ) ) )", ref="re1tbw1", note="re1tbw1")
    s4 = lb.mp("s4", s2, s3, "ax-mp")
    s5 = lb.mp("s5", s1, s4, "ax-mp")
    s6 = lb.ref("s6", "( ( ( φ → φ ) → φ ) → φ )", ref="re1tbw3", note="re1tbw3")
    s7 = lb.ref("s7", "( φ → ( ( φ → φ ) → φ ) )", ref="re1tbw2", note="re1tbw2")
    s8 = lb.ref("s8", "( ( φ → ( ( φ → φ ) → φ ) ) → ( ( ( ( φ → φ ) → φ ) → φ ) → ( φ → φ ) ) )", ref="re1tbw1", note="re1tbw1")
    s9 = lb.mp("s9", s7, s8, "ax-mp")
    s10 = lb.mp("s10", s6, s9, "ax-mp")
    s11 = lb.ref("s11", "( ( ( ( ⊥ → φ ) → φ ) → ( ⊥ → φ ) ) → ( ⊥ → φ ) )", ref="re1tbw3", note="re1tbw3")
    s12 = lb.ref("s12", "( ( ⊥ → φ ) → ( ( ( ⊥ → φ ) → φ ) → ( ⊥ → φ ) ) )", ref="re1tbw2", note="re1tbw2")
    s13 = lb.ref("s13", "( ( ( ⊥ → φ ) → ( ( ( ⊥ → φ ) → φ ) → ( ⊥ → φ ) ) ) → ( ( ( ( ( ⊥ → φ ) → φ ) → ( ⊥ → φ ) ) → ( ⊥ → φ ) ) → ( ( ⊥ → φ ) → ( ⊥ → φ ) ) ) )", ref="re1tbw1", note="re1tbw1")
    s14 = lb.mp("s14", s12, s13, "ax-mp")
    s15 = lb.mp("s15", s11, s14, "ax-mp")
    s16 = lb.ref("s16", "( ( ( ⊥ → φ ) → φ ) → ( ( ⊥ → φ ) → ( ⊥ → φ ) ) )", ref="mercolem3", note="mercolem3")
    s17 = lb.ref("s17", "( ( ( ( ⊥ → φ ) → φ ) → ( ( ⊥ → φ ) → ( ⊥ → φ ) ) ) → ( ( ( ⊥ → φ ) → ( ⊥ → φ ) ) → ( ( φ → φ ) → ( ( φ → φ ) → ( ⊥ → φ ) ) ) ) )", ref="merco2", note="merco2")
    s18 = lb.mp("s18", s16, s17, "ax-mp")
    s19 = lb.mp("s19", s15, s18, "ax-mp")
    s20 = lb.mp("s20", s10, s19, "ax-mp")
    res = lb.mp("res", s5, s20, "ax-mp")
    return lb.build(res)

def prove_rb_bijust(sys: System) -> Proof:
    """Justification for ~ rb-imdf .  (Contributed by Anthony Hart, 17-Aug-2011.)
    (Proof modification is discouraged.)  (New usage is discouraged.)
    """
    lb = ProofBuilder(sys, "rb-bijust")
    s1 = lb.ref("s1", "( ( φ ↔ ψ ) ↔ ¬ ( ( φ → ψ ) → ¬ ( ψ → φ ) ) )", ref="dfbi1", note="dfbi1")
    s2 = lb.ref("s2", "( ( φ → ψ ) ↔ ( ¬ φ ∨ ψ ) )", ref="imor", note="imor")
    s3 = lb.ref("s3", "( ( ψ → φ ) ↔ ( ¬ ψ ∨ φ ) )", ref="imor", note="imor")
    s4 = lb.ref("s4", "( ¬ ( ψ → φ ) ↔ ¬ ( ¬ ψ ∨ φ ) )", s3, ref="notbii", note="notbii")
    s5 = lb.ref("s5", "( ( ( φ → ψ ) → ¬ ( ψ → φ ) ) ↔ ( ( ¬ φ ∨ ψ ) → ¬ ( ¬ ψ ∨ φ ) ) )", s2, s4, ref="imbi12i", note="imbi12i")
    s6 = lb.ref("s6", "( ¬ ( ( φ → ψ ) → ¬ ( ψ → φ ) ) ↔ ¬ ( ( ¬ φ ∨ ψ ) → ¬ ( ¬ ψ ∨ φ ) ) )", s5, ref="notbii", note="notbii")
    s7 = lb.ref("s7", "( ( ( ¬ φ ∨ ψ ) → ¬ ( ¬ ψ ∨ φ ) ) ↔ ( ¬ ( ¬ φ ∨ ψ ) ∨ ¬ ( ¬ ψ ∨ φ ) ) )", ref="pm4.62", note="pm4.62")
    s8 = lb.ref("s8", "( ¬ ( ( ¬ φ ∨ ψ ) → ¬ ( ¬ ψ ∨ φ ) ) ↔ ¬ ( ¬ ( ¬ φ ∨ ψ ) ∨ ¬ ( ¬ ψ ∨ φ ) ) )", s7, ref="notbii", note="notbii")
    res = lb.ref("res", "( ( φ ↔ ψ ) ↔ ¬ ( ¬ ( ¬ φ ∨ ψ ) ∨ ¬ ( ¬ ψ ∨ φ ) ) )", s1, s6, s8, ref="3bitri", note="3bitri")
    return lb.build(res)

def prove_rb_imdf(sys: System) -> Proof:
    """The definition of implication, in terms of ` \\/ ` and ` -. ` .
    (Contributed by Anthony Hart, 17-Aug-2011.)
    (Proof modification is discouraged.)  (New usage is discouraged.)
    """
    lb = ProofBuilder(sys, "rb-imdf")
    s1 = lb.ref("s1", "( ( φ → ψ ) ↔ ( ¬ φ ∨ ψ ) )", ref="imor", note="imor")
    s2 = lb.ref("s2", "( ( ( φ → ψ ) ↔ ( ¬ φ ∨ ψ ) ) ↔ ¬ ( ¬ ( ¬ ( φ → ψ ) ∨ ( ¬ φ ∨ ψ ) ) ∨ ¬ ( ¬ ( ¬ φ ∨ ψ ) ∨ ( φ → ψ ) ) ) )", ref="rb-bijust", note="rb-bijust")
    res = lb.ref("res", "¬ ( ¬ ( ¬ ( φ → ψ ) ∨ ( ¬ φ ∨ ψ ) ) ∨ ¬ ( ¬ ( ¬ φ ∨ ψ ) ∨ ( φ → ψ ) ) )", s1, s2, ref="mpbi", note="mpbi")
    return lb.build(res)

def prove_anmp(sys: System) -> Proof:
    """Modus ponens for ` { \\/ , -. } ` axiom systems.  (Contributed by Anthony
    Hart, 12-Aug-2011.)  (Proof modification is discouraged.)
    (New usage is discouraged.)
    """
    lb = ProofBuilder(sys, "anmp")
    h1 = lb.hyp("anmp.min", "φ")
    h2 = lb.hyp("anmp.maj", "( ¬ φ ∨ ψ )")
    s1 = lb.ref("s1", "( φ → ψ )", h2, ref="imorri", note="imorri")
    res = lb.mp("res", h1, s1, "ax-mp")
    return lb.build(res)

def prove_rb_ax1(sys: System) -> Proof:
    """The first of four axioms in the Russell-Bernays axiom system.
    (Contributed by Anthony Hart, 13-Aug-2011.)
    (Proof modification is discouraged.)  (New usage is discouraged.)
    """
    lb = ProofBuilder(sys, "rb-ax1")
    s1 = lb.ref("s1", "( ( ψ → χ ) → ( ( φ ∨ ψ ) → ( φ ∨ χ ) ) )", ref="orim2", note="orim2")
    s2 = lb.ref("s2", "( ( ψ → χ ) ↔ ( ¬ ψ ∨ χ ) )", ref="imor", note="imor")
    s3 = lb.ref("s3", "( ( ( φ ∨ ψ ) → ( φ ∨ χ ) ) ↔ ( ¬ ( φ ∨ ψ ) ∨ ( φ ∨ χ ) ) )", ref="imor", note="imor")
    s4 = lb.ref("s4", "( ( ¬ ψ ∨ χ ) → ( ¬ ( φ ∨ ψ ) ∨ ( φ ∨ χ ) ) )", s1, s2, s3, ref="3imtr3i", note="3imtr3i")
    res = lb.ref("res", "( ¬ ( ¬ ψ ∨ χ ) ∨ ( ¬ ( φ ∨ ψ ) ∨ ( φ ∨ χ ) ) )", s4, ref="imori", note="imori")
    return lb.build(res)

def prove_rb_ax2(sys: System) -> Proof:
    """The second of four axioms in the Russell-Bernays axiom system.
    (Contributed by Anthony Hart, 13-Aug-2011.)
    (Proof modification is discouraged.)  (New usage is discouraged.)
    """
    lb = ProofBuilder(sys, "rb-ax2")
    s1 = lb.ref("s1", "( ( φ ∨ ψ ) → ( ψ ∨ φ ) )", ref="pm1.4", note="pm1.4")
    s2 = lb.ref("s2", "( ¬ ( ψ ∨ φ ) → ¬ ( φ ∨ ψ ) )", s1, ref="con3i", note="con3i")
    s3 = lb.ref("s3", "( ¬ ¬ ( φ ∨ ψ ) → ( ψ ∨ φ ) )", s2, ref="con1i", note="con1i")
    res = lb.ref("res", "( ¬ ( φ ∨ ψ ) ∨ ( ψ ∨ φ ) )", s3, ref="orri", note="orri")
    return lb.build(res)

def prove_rb_ax3(sys: System) -> Proof:
    """The third of four axioms in the Russell-Bernays axiom system.
    (Contributed by Anthony Hart, 13-Aug-2011.)
    (Proof modification is discouraged.)  (New usage is discouraged.)
    """
    lb = ProofBuilder(sys, "rb-ax3")
    s1 = lb.ref("s1", "( ¬ ( ψ ∨ φ ) → ¬ φ )", ref="pm2.46", note="pm2.46")
    s2 = lb.ref("s2", "( ¬ ¬ φ → ( ψ ∨ φ ) )", s1, ref="con1i", note="con1i")
    res = lb.ref("res", "( ¬ φ ∨ ( ψ ∨ φ ) )", s2, ref="orri", note="orri")
    return lb.build(res)

def prove_rb_ax4(sys: System) -> Proof:
    """The fourth of four axioms in the Russell-Bernays axiom system.
    (Contributed by Anthony Hart, 13-Aug-2011.)
    (Proof modification is discouraged.)  (New usage is discouraged.)
    """
    lb = ProofBuilder(sys, "rb-ax4")
    s1 = lb.ref("s1", "( ( φ ∨ φ ) → φ )", ref="pm1.2", note="pm1.2")
    s2 = lb.ref("s2", "( ¬ φ → ¬ ( φ ∨ φ ) )", s1, ref="con3i", note="con3i")
    s3 = lb.ref("s3", "( ¬ ¬ ( φ ∨ φ ) → φ )", s2, ref="con1i", note="con1i")
    res = lb.ref("res", "( ¬ ( φ ∨ φ ) ∨ φ )", s3, ref="orri", note="orri")
    return lb.build(res)

def prove_rbsyl(sys: System) -> Proof:
    """Used to rederive the Lukasiewicz axioms from Russell-Bernays'.
    (Contributed by Anthony Hart, 18-Aug-2011.)
    (Proof modification is discouraged.)  (New usage is discouraged.)
    """
    lb = ProofBuilder(sys, "rbsyl")
    h1 = lb.hyp("rbsyl.1", "( ¬ ψ ∨ χ )")
    h2 = lb.hyp("rbsyl.2", "( φ ∨ ψ )")
    s1 = lb.ref("s1", "( ¬ ( ¬ ψ ∨ χ ) ∨ ( ¬ ( φ ∨ ψ ) ∨ ( φ ∨ χ ) ) )", ref="rb-ax1", note="rb-ax1")
    s2 = lb.ref("s2", "( ¬ ( φ ∨ ψ ) ∨ ( φ ∨ χ ) )", h1, s1, ref="anmp", note="anmp")
    res = lb.ref("res", "( φ ∨ χ )", h2, s2, ref="anmp", note="anmp")
    return lb.build(res)

def prove_rblem1(sys: System) -> Proof:
    """Used to rederive the Lukasiewicz axioms from Russell-Bernays'.
    (Contributed by Anthony Hart, 18-Aug-2011.)
    (Proof modification is discouraged.)  (New usage is discouraged.)
    """
    lb = ProofBuilder(sys, "rblem1")
    h1 = lb.hyp("rblem1.1", "( ¬ φ ∨ ψ )")
    h2 = lb.hyp("rblem1.2", "( ¬ χ ∨ θ )")
    s1 = lb.ref("s1", "( ¬ ( ¬ χ ∨ θ ) ∨ ( ¬ ( ψ ∨ χ ) ∨ ( ψ ∨ θ ) ) )", ref="rb-ax1", note="rb-ax1")
    s2 = lb.ref("s2", "( ¬ ( ψ ∨ χ ) ∨ ( ψ ∨ θ ) )", h2, s1, ref="anmp", note="anmp")
    s3 = lb.ref("s3", "( ¬ ( χ ∨ ψ ) ∨ ( ψ ∨ χ ) )", ref="rb-ax2", note="rb-ax2")
    s4 = lb.ref("s4", "( ¬ ( ¬ φ ∨ ψ ) ∨ ( ¬ ( χ ∨ φ ) ∨ ( χ ∨ ψ ) ) )", ref="rb-ax1", note="rb-ax1")
    s5 = lb.ref("s5", "( ¬ ( χ ∨ φ ) ∨ ( χ ∨ ψ ) )", h1, s4, ref="anmp", note="anmp")
    s6 = lb.ref("s6", "( ¬ ( φ ∨ χ ) ∨ ( χ ∨ φ ) )", ref="rb-ax2", note="rb-ax2")
    s7 = lb.ref("s7", "( ¬ ( φ ∨ χ ) ∨ ( χ ∨ ψ ) )", s5, s6, ref="rbsyl", note="rbsyl")
    s8 = lb.ref("s8", "( ¬ ( φ ∨ χ ) ∨ ( ψ ∨ χ ) )", s3, s7, ref="rbsyl", note="rbsyl")
    res = lb.ref("res", "( ¬ ( φ ∨ χ ) ∨ ( ψ ∨ θ ) )", s2, s8, ref="rbsyl", note="rbsyl")
    return lb.build(res)

def prove_rblem2(sys: System) -> Proof:
    """Used to rederive the Lukasiewicz axioms from Russell-Bernays'.
    (Contributed by Anthony Hart, 18-Aug-2011.)
    (Proof modification is discouraged.)  (New usage is discouraged.)
    """
    lb = ProofBuilder(sys, "rblem2")
    s1 = lb.ref("s1", "( ¬ ( ψ ∨ φ ) ∨ ( φ ∨ ψ ) )", ref="rb-ax2", note="rb-ax2")
    s2 = lb.ref("s2", "( ¬ φ ∨ ( ψ ∨ φ ) )", ref="rb-ax3", note="rb-ax3")
    s3 = lb.ref("s3", "( ¬ φ ∨ ( φ ∨ ψ ) )", s1, s2, ref="rbsyl", note="rbsyl")
    s4 = lb.ref("s4", "( ¬ ( ¬ φ ∨ ( φ ∨ ψ ) ) ∨ ( ¬ ( χ ∨ φ ) ∨ ( χ ∨ ( φ ∨ ψ ) ) ) )", ref="rb-ax1", note="rb-ax1")
    res = lb.ref("res", "( ¬ ( χ ∨ φ ) ∨ ( χ ∨ ( φ ∨ ψ ) ) )", s3, s4, ref="anmp", note="anmp")
    return lb.build(res)

def prove_rblem3(sys: System) -> Proof:
    """Used to rederive the Lukasiewicz axioms from Russell-Bernays'.
    (Contributed by Anthony Hart, 18-Aug-2011.)
    (Proof modification is discouraged.)  (New usage is discouraged.)
    """
    lb = ProofBuilder(sys, "rblem3")
